#!/bin/bash

# .chezmoidata/packages.yaml hash: {{ include ".chezmoidata/packages.yaml" | sha256sum }}

# Exit on error
set -e

# Ensure Homebrew is in PATH
if ! command -v brew &> /dev/null; then
    if [ -x /home/linuxbrew/.linuxbrew/bin/brew ]; then
        eval "$(/home/linuxbrew/.linuxbrew/bin/brew shellenv)"
    elif [ -x /opt/homebrew/bin/brew ]; then
        eval "$(/opt/homebrew/bin/brew shellenv)"
    elif [ -x /usr/local/bin/brew ]; then
        eval "$(/usr/local/bin/brew shellenv)"
    fi
fi

# --- Linux APT phase ---
{{ if eq .chezmoi.os "linux" -}}
if command -v apt-get &> /dev/null; then
    echo "Updating and installing APT packages..."
    # sudo apt-get update # Removed for speed, assuming system is up to date
    sudo apt-get install -y {{ range .packages.apt }}{{ . }} {{ end }}
fi
{{- end }}

# --- Homebrew phase (Both macOS and Linux) ---
if command -v brew &> /dev/null; then
    echo "Applying Homebrew bundle..."
    brew bundle --file=/dev/stdin <<EOF
{{ range .packages.taps -}}
tap {{ . | quote }}
{{ end }}

# CLI Tools (Brews)
{{ range .packages.brews.base -}}
brew {{ . | quote }}
{{ end }}

{{ if or (eq .stack "container") (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.container -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.development -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if .media -}}
{{ range .packages.brews.media -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "container") (eq .stack "development") (eq .stack "full") -}}
{{ range .packages.brews.standard_cli -}}
brew {{ . | quote }}
{{ end }}
{{- end }}

{{ if eq .chezmoi.os "darwin" -}}
# macOS-specific CLI tools
{{ range .packages.brews.macos -}}
brew {{ . | quote }}
{{ end }}

# CLI Casks
{{ range .packages.casks.cli -}}
cask {{ . | quote }}
{{ end }}

# Fonts
{{ range .packages.casks.fonts -}}
cask {{ . | quote }}
{{ end }}

# Essential macOS GUI apps
{{ range .packages.casks.macos -}}
cask {{ . | quote }}
{{ end }}

{{ if .personal -}}
# Personal/Identity GUI apps
{{ range .packages.casks.personal -}}
cask {{ . | quote }}
{{ end }}
{{- end }}

{{ if or (eq .stack "development") (eq .stack "full") -}}
# Developer GUI apps
{{ range .packages.casks.development -}}
cask {{ . | quote }}
{{ end }}
{{- end }}

{{ if .workstation -}}
# Workstation/Hardware GUI apps
{{ range .packages.casks.workstation -}}
cask {{ . | quote }}
{{ end }}
{{- end }}
{{- end }}
EOF
fi

# --- Linux-specific non-brew phase ---
{{ if eq .chezmoi.os "linux" -}}

# Install NPM tools on Linux development/full stack
{{ if or (eq .stack "development") (eq .stack "full") -}}
if command -v npm &> /dev/null; then
    echo "Installing NPM global packages..."
    {{ range .packages.linux.npm -}}
    # Check if we need sudo for global npm install
    if [ -w "$(npm config get prefix)/lib/node_modules" ] 2>/dev/null || [ -w "$(npm config get prefix)/bin" ] 2>/dev/null; then
        npm install -g {{ . | quote }}
    else
        sudo npm install -g {{ . | quote }}
    fi
    {{ end }}
fi
{{- end }}

# Run custom Linux install scripts
{{ range .packages.linux.scripts -}}
echo "Running custom install script: {{ .name }}..."
{{ .command }}
{{ end }}

{{- end }}

# Custom Tool Initializations
if command -v rtk &> /dev/null; then
    echo "Initializing RTK..."
    {{ range .packages.init.rtk -}}
    {{ . }} || true
    {{ end }}
fi

